from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session

from app.api.deps import get_db
from app.schemas.report import ReportCreate, ReportResponse
from app.services import report_service

router = APIRouter(prefix="/reports")


@router.post("", response_model=ReportResponse, status_code=201)
def create_report(report: ReportCreate, db: Session = Depends(get_db)):
    """Submit a housekeeping report with photos and voice note."""
    return report_service.create_report(db, report)


@router.get("", response_model=list[ReportResponse])
def list_reports(skip: int = 0, limit: int = 50, db: Session = Depends(get_db)):
    """List recent housekeeping reports."""
    return report_service.get_reports(db, skip=skip, limit=limit)

