/* ============================================
   HOUSEKEEPING REPORT — Mobile-first UI
   Elderly-friendly, large touch targets
   ============================================ */

/* Reset */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

:root {
    --font: 'Nunito', sans-serif;

    /* Brand Colors */
    --blue: #4A90FF;
    --blue-dark: #2D6FCC;
    --blue-light: #E8F4FF;
    --blue-shadow: rgba(74,144,255,0.18);

    /* Neutrals */
    --bg: #F8F9FB;
    --white: #FFFFFF;
    --text: #111111;
    --text-mid: #333333;
    --text-muted: #6B7280;
    --border: #D1E3FF;

    /* Status */
    --green: #22C55E;
    --red: #EF4444;

    /* Spacing */
    --pad: 16px;
    --gap: 24px;
    --radius-xl: 20px;
    --radius-lg: 16px;
    --radius-md: 12px;
    --radius-full: 999px;

    /* Transitions */
    --fast: 150ms ease;
    --normal: 250ms ease;
}

html, body {
    height: 100%;
    width: 100%;
    font-family: var(--font);
    color: var(--text);
    background: var(--bg);
    -webkit-font-smoothing: antialiased;
    overflow: hidden; /* screens handle scroll */
}

/* ============================================
   SCREEN SYSTEM
   ============================================ */

.screen {
    position: fixed;
    inset: 0;
    display: flex;
    flex-direction: column;
    background: linear-gradient(160deg, #F0F7FF 0%, #FFFFFF 60%);
    opacity: 0;
    pointer-events: none;
    transform: translateX(30px);
    transition: opacity var(--normal), transform var(--normal);
    z-index: 1;
    overflow: hidden;
}

.screen.active {
    opacity: 1;
    pointer-events: all;
    transform: translateX(0);
    z-index: 2;
}

.screen.slide-out {
    opacity: 0;
    transform: translateX(-30px);
    pointer-events: none;
    z-index: 1;
}

/* ============================================
   SCREEN 1 — ROOM INPUT
   ============================================ */

.screen-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: var(--pad);
    overflow-y: auto;
}

.app-logo {
    margin-top: 40px;
    text-align: center;
}

.logo-icon {
    font-size: 56px;
    line-height: 1;
    animation: floatIn 0.6s ease both;
}

.logo-label {
    font-size: 13px;
    font-weight: 700;
    color: var(--blue);
    letter-spacing: 2px;
    text-transform: uppercase;
    margin-top: 6px;
    animation: floatIn 0.6s 0.1s ease both;
}

@keyframes floatIn {
    from { opacity: 0; transform: translateY(12px); }
    to   { opacity: 1; transform: translateY(0); }
}

.main-card {
    width: 100%;
    max-width: 440px;
    background: var(--blue-light);
    border-radius: var(--radius-xl);
    box-shadow: 0 8px 24px var(--blue-shadow);
    padding: 28px 24px;
    margin-top: 32px;
    animation: floatIn 0.6s 0.15s ease both;
}

.screen-title {
    font-size: 22px;
    font-weight: 800;
    color: var(--text);
    text-align: center;
    margin-bottom: 6px;
}

.screen-subtitle {
    font-size: 14px;
    color: var(--text-muted);
    text-align: center;
    margin-bottom: 24px;
    line-height: 1.5;
}

.input-wrap {
    display: flex;
    justify-content: center;
}

.room-input-field {
    width: 100%;
    height: 64px;
    border-radius: var(--radius-lg);
    border: 2.5px solid var(--border);
    background: var(--white);
    font-family: var(--font);
    font-size: 28px;
    font-weight: 800;
    color: var(--blue-dark);
    text-align: center;
    letter-spacing: 3px;
    outline: none;
    transition: border-color var(--fast), box-shadow var(--fast);
    padding: 0 16px;
}

.room-input-field::placeholder {
    color: #B0C4DE;
    font-weight: 600;
    letter-spacing: 1px;
}

.room-input-field:focus {
    border-color: var(--blue);
    box-shadow: 0 0 0 4px rgba(74,144,255,0.15);
}

/* ============================================
   BUTTONS
   ============================================ */

.btn-primary {
    width: 100%;
    height: 56px;
    border: none;
    border-radius: var(--radius-full);
    background: var(--blue);
    color: var(--white);
    font-family: var(--font);
    font-size: 18px;
    font-weight: 800;
    cursor: pointer;
    box-shadow: 0 6px 20px rgba(74,144,255,0.4);
    transition: transform var(--fast), background var(--fast), box-shadow var(--fast);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    letter-spacing: 0.5px;
}

.btn-primary:active {
    transform: scale(0.97);
    background: var(--blue-dark);
    box-shadow: 0 2px 8px rgba(74,144,255,0.3);
}

.btn-primary:disabled {
    background: #B0C4DE;
    box-shadow: none;
    cursor: not-allowed;
    transform: none;
}

.btn-secondary {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 12px 24px;
    border: 2px solid var(--blue);
    border-radius: var(--radius-full);
    background: var(--white);
    color: var(--blue);
    font-family: var(--font);
    font-size: 16px;
    font-weight: 700;
    cursor: pointer;
    transition: transform var(--fast), background var(--fast);
}

.btn-secondary:active {
    transform: scale(0.97);
    background: var(--blue-light);
}

.bottom-action {
    width: 100%;
    max-width: 440px;
    padding: 24px var(--pad) 32px;
    margin-top: auto;
    animation: floatIn 0.6s 0.25s ease both;
}

.bottom-action.sticky {
    position: sticky;
    bottom: 0;
    background: linear-gradient(to top, rgba(255,255,255,0.98) 70%, transparent);
    padding-top: 16px;
    max-width: 100%;
    padding-left: var(--pad);
    padding-right: var(--pad);
}

/* ============================================
   SCREEN HEADER (shared: camera + report)
   ============================================ */

.screen-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px var(--pad);
    background: var(--white);
    box-shadow: 0 2px 12px rgba(0,0,0,0.06);
    flex-shrink: 0;
}

.btn-back {
    width: 44px;
    height: 44px;
    border: none;
    border-radius: 50%;
    background: var(--blue-light);
    color: var(--blue);
    font-size: 26px;
    font-weight: 800;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform var(--fast), background var(--fast);
    flex-shrink: 0;
}

.btn-back:active {
    transform: scale(0.92);
    background: var(--border);
}

.header-info {
    text-align: center;
    flex: 1;
}

.header-room-id {
    font-size: 17px;
    font-weight: 900;
    color: var(--blue-dark);
    letter-spacing: 1.5px;
}

.header-sub {
    font-size: 12px;
    color: var(--text-muted);
    margin-top: 1px;
}

.photo-counter {
    font-size: 15px;
    font-weight: 800;
    color: var(--blue);
    background: var(--blue-light);
    padding: 6px 12px;
    border-radius: var(--radius-full);
    flex-shrink: 0;
}

/* ============================================
   SCREEN 2 — CAMERA
   ============================================ */

.camera-area {
    flex: 1;
    position: relative;
    background: #000;
    overflow: hidden;
    min-height: 0;
}

#camera-video {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
}

.camera-overlay {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none;
}

.camera-frame {
    width: min(75vw, 280px);
    height: min(75vw, 280px);
    border: 3px solid rgba(255,255,255,0.6);
    border-radius: 24px;
    box-shadow: 0 0 0 2000px rgba(0,0,0,0.25);
}

.camera-fallback {
    position: absolute;
    inset: 0;
    background: #1a1a2e;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    color: #fff;
}

.fallback-icon { font-size: 64px; }

.camera-controls {
    background: var(--white);
    padding: 16px var(--pad) 28px;
    flex-shrink: 0;
}

.thumbnail-row {
    display: flex;
    gap: 10px;
    margin-bottom: 16px;
    min-height: 72px;
    align-items: center;
    overflow-x: auto;
    scrollbar-width: none;
}

.thumbnail-row::-webkit-scrollbar { display: none; }

.thumb-slot {
    width: 72px;
    height: 72px;
    border-radius: var(--radius-md);
    border: 2px dashed var(--border);
    background: var(--blue-light);
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--text-muted);
    font-size: 22px;
}

.thumb-item {
    position: relative;
    width: 72px;
    height: 72px;
    flex-shrink: 0;
    border-radius: var(--radius-md);
    overflow: hidden;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    animation: popIn 0.25s ease both;
}

@keyframes popIn {
    from { transform: scale(0.7); opacity: 0; }
    to   { transform: scale(1); opacity: 1; }
