}

.voice-status {
    font-size: 15px;
    font-weight: 700;
    color: var(--text-mid);
}

.voice-waves {
    display: flex;
    align-items: center;
    gap: 4px;
    height: 28px;
}

.voice-waves span {
    display: block;
    width: 5px;
    border-radius: 3px;
    background: var(--red);
    animation: wave 0.8s ease infinite;
    height: 10px;
}

.voice-waves span:nth-child(1) { animation-delay: 0s; }
.voice-waves span:nth-child(2) { animation-delay: 0.1s; }
.voice-waves span:nth-child(3) { animation-delay: 0.2s; }
.voice-waves span:nth-child(4) { animation-delay: 0.3s; }
.voice-waves span:nth-child(5) { animation-delay: 0.4s; }

@keyframes wave {
    0%, 100% { height: 10px; }
    50% { height: 26px; }
}

.voice-text-wrap {
    margin-top: 4px;
}

.voice-textarea {
    width: 100%;
    border: 2px solid var(--border);
    border-radius: var(--radius-md);
    background: var(--white);
    font-family: var(--font);
    font-size: 15px;
    color: var(--text-mid);
    padding: 12px;
    resize: none;
    outline: none;
    line-height: 1.6;
    transition: border-color var(--fast);
}

.voice-textarea:focus {
    border-color: var(--blue);
}

.btn-submit {
    font-size: 18px;
    gap: 10px;
}

.spinner-inline {
    width: 20px;
    height: 20px;
    border: 3px solid rgba(255,255,255,0.4);
    border-top-color: #fff;
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
    flex-shrink: 0;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

/* ============================================
   SCREEN 4 — SUCCESS
   ============================================ */

.success-content {
    justify-content: center;
    gap: 20px;
    padding: 40px var(--pad);
    text-align: center;
}

.success-animation {
    position: relative;
    width: 130px;
    height: 130px;
    margin: 0 auto 8px;
}

.success-circle {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    background: var(--green);
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 5px;
    box-shadow: 0 8px 28px rgba(34,197,94,0.4);
    animation: successPop 0.5s cubic-bezier(0.34,1.56,0.64,1) both;
}

.success-icon {
    font-size: 52px;
    color: #fff;
    font-weight: 900;
    font-style: normal;
}

.success-ripple {
    position: absolute;
    inset: 0;
    border-radius: 50%;
    border: 3px solid var(--green);
    animation: ripple 1.2s ease 0.5s both;
}

@keyframes successPop {
    from { transform: scale(0.5); opacity: 0; }
    to   { transform: scale(1); opacity: 1; }
}

@keyframes ripple {
    from { transform: scale(0.9); opacity: 0.8; }
    to   { transform: scale(1.6); opacity: 0; }
}

.success-title {
    font-size: 24px;
    font-weight: 900;
    color: var(--text);
    animation: floatIn 0.5s 0.3s ease both;
}

.success-room {
    font-size: 17px;
    font-weight: 700;
    color: var(--blue);
    animation: floatIn 0.5s 0.4s ease both;
}

.success-time {
    font-size: 13px;
    color: var(--text-muted);
    animation: floatIn 0.5s 0.45s ease both;
}

.success-content .btn-primary {
    margin-top: 12px;
    animation: floatIn 0.5s 0.55s ease both;
}

/* ============================================
   TOAST
   ============================================ */

.toast {
    position: fixed;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%) translateY(20px);
    background: #1a1a1a;
    color: #fff;
    padding: 13px 24px;
    border-radius: var(--radius-full);
    font-size: 14px;
    font-weight: 700;
    font-family: var(--font);
    z-index: 9999;
    opacity: 0;
    transition: opacity 0.25s, transform 0.25s;
    white-space: nowrap;
    max-width: calc(100vw - 32px);
    text-align: center;
    pointer-events: none;
}

.toast.show {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
}

/* ============================================
   UTILITIES
   ============================================ */

.hidden { display: none !important; }
