/**
 * Housekeeping Report App
 * 4-screen linear flow: Room Input → Camera → Report → Success
 */

// ============================================================
// STATE
// ============================================================
const state = {
    roomId: '',
    photos: [],       // Array of { dataUrl, blob, s3Url }
    voiceText: '',
    stream: null,     // MediaStream for camera
};

// ============================================================
// UTILITIES
// ============================================================

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = String(text);
    return div.innerHTML;
}

let toastTimer = null;
function showToast(msg, duration = 2800) {
    const el = document.getElementById('toast');
    el.textContent = msg;
    el.classList.remove('hidden');
    el.classList.add('show');
    clearTimeout(toastTimer);
    toastTimer = setTimeout(() => {
        el.classList.remove('show');
        setTimeout(() => el.classList.add('hidden'), 300);
    }, duration);
}

// ============================================================
// SCREEN NAVIGATION
// ============================================================

function showScreen(id) {
    const current = document.querySelector('.screen.active');
    const next = document.getElementById(id);
    if (!next || current === next) return;

    if (current) {
        current.classList.add('slide-out');
        setTimeout(() => current.classList.remove('active', 'slide-out'), 300);
    }

    setTimeout(() => {
        next.classList.add('active');
    }, 50);
}

// ============================================================
// SCREEN 1 — ROOM INPUT
// ============================================================

const roomInput = document.getElementById('room-input');
const btnContinueRoom = document.getElementById('btn-continue-room');

roomInput.addEventListener('input', () => {
    btnContinueRoom.disabled = roomInput.value.trim().length === 0;
});

roomInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !btnContinueRoom.disabled) {
        goToCamera();
    }
});

btnContinueRoom.addEventListener('click', goToCamera);

function goToCamera() {
    const val = roomInput.value.trim();
    if (!val) {
        showToast('Vui lòng nhập mã phòng');
        roomInput.focus();
        return;
    }
    state.roomId = val.toUpperCase();
    state.photos = [];

    // Update labels
    document.getElementById('camera-room-label').textContent = 'PHÒNG ' + state.roomId;
    document.getElementById('report-room-label').textContent = 'PHÒNG ' + state.roomId;

    showScreen('screen-camera');
    startCamera();
}

// ============================================================
// SCREEN 2 — CAMERA
// ============================================================

const video = document.getElementById('camera-video');
const canvas = document.getElementById('camera-canvas');
const btnShutter = document.getElementById('btn-shutter');
const thumbnailRow = document.getElementById('thumbnail-row');
const photoCounter = document.getElementById('photo-counter');
const btnNextReport = document.getElementById('btn-next-report');
const cameraFallback = document.getElementById('camera-fallback');
const fileInputFallback = document.getElementById('file-input-fallback');
const MAX_PHOTOS = 3;

async function startCamera() {
    try {
        if (state.stream) {
            state.stream.getTracks().forEach(t => t.stop());
        }
        const stream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } },
            audio: false,
        });
        state.stream = stream;
        video.srcObject = stream;
        video.classList.remove('hidden');
        cameraFallback.classList.add('hidden');
    } catch (err) {
        console.warn('Camera not available:', err);
        video.classList.add('hidden');
        cameraFallback.classList.remove('hidden');
    }
    renderThumbnails();
    updateCameraUI();
}

function stopCamera() {
    if (state.stream) {
        state.stream.getTracks().forEach(t => t.stop());
        state.stream = null;
    }
}

document.getElementById('btn-back-camera').addEventListener('click', () => {
    stopCamera();
    showScreen('screen-room-input');
    setTimeout(() => roomInput.focus(), 350);
});

btnShutter.addEventListener('click', capturePhoto);

function capturePhoto() {
    if (state.photos.length >= MAX_PHOTOS) return;

    // Flash effect
    const overlay = document.getElementById('camera-overlay');
    overlay.style.background = 'rgba(255,255,255,0.7)';
    setTimeout(() => overlay.style.background = '', 150);

    // Draw video frame to canvas
    canvas.width = video.videoWidth || 1280;
    canvas.height = video.videoHeight || 720;
    const ctx = canvas.getContext('2d');
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    canvas.toBlob((blob) => {
        const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
        state.photos.push({ dataUrl, blob, s3Url: null });
        renderThumbnails();
        updateCameraUI();

        if (state.photos.length >= MAX_PHOTOS) {
            setTimeout(goToReport, 600);
        }
    }, 'image/jpeg', 0.85);
}

// Fallback file input
fileInputFallback.addEventListener('change', (e) => {
    const files = Array.from(e.target.files).slice(0, MAX_PHOTOS - state.photos.length);
    files.forEach(file => {
        const reader = new FileReader();
        reader.onload = (ev) => {
            state.photos.push({ dataUrl: ev.target.result, blob: file, s3Url: null });
            renderThumbnails();
            updateCameraUI();
            if (state.photos.length >= MAX_PHOTOS) {
                setTimeout(goToReport, 600);
            }
        };
        reader.readAsDataURL(file);
    });
    e.target.value = '';
});

function renderThumbnails() {
    thumbnailRow.innerHTML = '';
    state.photos.forEach((photo, i) => {
        const item = document.createElement('div');
        item.className = 'thumb-item';
        item.innerHTML = `
            <img src="${photo.dataUrl}" alt="Ảnh ${i + 1}">
            <button class="thumb-delete" data-index="${i}" aria-label="Xóa ảnh">✕</button>
        `;
        thumbnailRow.appendChild(item);
    });

    // Empty slots
    for (let i = state.photos.length; i < MAX_PHOTOS; i++) {
        const slot = document.createElement('div');
        slot.className = 'thumb-slot';
        slot.textContent = '📷';
        thumbnailRow.appendChild(slot);
    }

    // Delete handlers
    thumbnailRow.querySelectorAll('.thumb-delete').forEach(btn => {
        btn.addEventListener('click', (e) => {
            const idx = parseInt(btn.dataset.index);
            state.photos.splice(idx, 1);
            renderThumbnails();
            updateCameraUI();
        });
    });
}

function updateCameraUI() {
    const count = state.photos.length;
    photoCounter.textContent = `${count} / ${MAX_PHOTOS}`;
    btnShutter.disabled = count >= MAX_PHOTOS;

    if (count > 0 && count < MAX_PHOTOS) {
        btnNextReport.classList.remove('hidden');
    } else {
        btnNextReport.classList.add('hidden');
    }
}

btnNextReport.addEventListener('click', goToReport);

function goToReport() {
    if (state.photos.length === 0) {
        showToast('Vui lòng chụp ít nhất 1 ảnh');
        return;
    }
    stopCamera();
    renderReportPhotos();
    showScreen('screen-report');
}

// ============================================================
// SCREEN 3 — REPORT
// ============================================================

document.getElementById('btn-back-report').addEventListener('click', () => {
    showScreen('screen-camera');
    startCamera();
});

function renderReportPhotos() {
    const container = document.getElementById('report-photos');
    container.innerHTML = state.photos.map((p, i) =>
        `<img class="report-photo-thumb" src="${p.dataUrl}" alt="Ảnh ${i + 1}">`
    ).join('');
}

// Voice recording
const btnMic = document.getElementById('btn-mic');
const voiceStatus = document.getElementById('voice-status');
const voiceWaves = document.getElementById('voice-waves');
const voiceTextarea = document.getElementById('voice-text');

let recognition = null;
let isRecording = false;

function setupSpeechRecognition() {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) return null;

    const rec = new SpeechRecognition();
    rec.lang = 'vi-VN';
    rec.continuous = true;
    rec.interimResults = true;

    let finalTranscript = '';

    rec.onresult = (event) => {
        let interim = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
            const transcript = event.results[i][0].transcript;
            if (event.results[i].isFinal) {
                finalTranscript += transcript + ' ';
            } else {
                interim = transcript;
            }
        }
        voiceTextarea.value = finalTranscript + interim;
    };

    rec.onerror = (event) => {
        console.warn('Speech error:', event.error);
        if (event.error === 'not-allowed') {
            showToast('Không có quyền truy cập microphone');
        }
        stopRecording();
    };

    rec.onend = () => {
        if (isRecording) stopRecording();
    };

    return rec;
}

function startRecording() {
    recognition = setupSpeechRecognition();
    if (!recognition) {
        showToast('Trình duyệt không hỗ trợ ghi âm. Vui lòng nhập tay.');
        return;
    }
    isRecording = true;
    recognition.start();
    btnMic.classList.add('recording');
    voiceStatus.textContent = '🔴 Đang ghi âm... (nhấn để dừng)';
    voiceWaves.classList.remove('hidden');
}

function stopRecording() {
    isRecording = false;
    if (recognition) {
        recognition.stop();
        recognition = null;
    }
    btnMic.classList.remove('recording');
    voiceStatus.textContent = 'Nhấn để ghi âm lại';
    voiceWaves.classList.add('hidden');
}

btnMic.addEventListener('click', () => {
    if (isRecording) {
        stopRecording();
    } else {
        startRecording();
    }
});

// Submit
document.getElementById('btn-submit').addEventListener('click', submitReport);

async function submitReport() {
    if (state.photos.length === 0) {
        showToast('Vui lòng chụp ít nhất 1 ảnh');
        return;
    }

    stopRecording();
    const voiceText = voiceTextarea.value.trim();

    // UI: loading state
    const btnSubmitText = document.getElementById('btn-submit-text');
    const submitSpinner = document.getElementById('submit-spinner');
    const btnSubmit = document.getElementById('btn-submit');
    btnSubmit.disabled = true;
    btnSubmitText.textContent = 'Đang tải ảnh...';
    submitSpinner.classList.remove('hidden');

    try {
        // Upload photos to S3
        const imageUrls = [];
        for (let i = 0; i < state.photos.length; i++) {
            const photo = state.photos[i];
            btnSubmitText.textContent = `Tải ảnh ${i + 1}/${state.photos.length}...`;

            const filename = `housekeeping/${state.roomId}_${Date.now()}_${i}.jpg`;
            const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });

            await fetch(upload_url, {
                method: 'PUT',
                body: photo.blob,
                headers: { 'Content-Type': 'image/jpeg' },
            });

            imageUrls.push(file_url);
        }

        // Submit report
        btnSubmitText.textContent = 'Đang gửi báo cáo...';
        await api.post('/api/reports', {
            room_id: state.roomId,
            image_urls: imageUrls,
            voice_text: voiceText || null,
        });

        goToSuccess();

    } catch (err) {
        console.error('Submit error:', err);
        showToast('Lỗi: ' + (err.message || 'Không thể gửi báo cáo'));
    } finally {
        btnSubmit.disabled = false;
        btnSubmitText.textContent = 'Gửi báo cáo ✓';
        submitSpinner.classList.add('hidden');
    }
}

