    document.getElementById('success-room-text').textContent =
        `Phòng ${state.roomId} đã được ghi nhận`;

    const now = new Date();
    document.getElementById('success-time').textContent =
        now.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' }) + ' · ' +
        now.toLocaleDateString('vi-VN');

    showScreen('screen-success');

    // Auto redirect after 5s
    setTimeout(() => {
        const successScreen = document.getElementById('screen-success');
        if (successScreen.classList.contains('active')) {
            resetAndGoHome();
        }
    }, 5000);
}

