fileInputFallback.addEventListener('change', (e) => {
    const files = Array.from(e.target.files).slice(0, MAX_PHOTOS - state.photos.length);
    files.forEach(file => {
        const reader = new FileReader();
        reader.onload = (ev) => {
            state.photos.push({ dataUrl: ev.target.result, blob: file, s3Url: null });
            renderThumbnails();
            updateCameraUI();
            if (state.photos.length >= MAX_PHOTOS) {
                setTimeout(goToReport, 600);
            }
        };
        reader.readAsDataURL(file);
    });
    e.target.value = '';
});

function renderThumbnails() {
    thumbnailRow.innerHTML = '';
    state.photos.forEach((photo, i) => {
        const item = document.createElement('div');
        item.className = 'thumb-item';
        item.innerHTML = `
            <img src="${photo.dataUrl}" alt="Ảnh ${i + 1}">
            <button class="thumb-delete" data-index="${i}" aria-label="Xóa ảnh">✕</button>
        `;
        thumbnailRow.appendChild(item);
    });

    // Empty slots
    for (let i = state.photos.length; i < MAX_PHOTOS; i++) {
        const slot = document.createElement('div');
        slot.className = 'thumb-slot';
        slot.textContent = '📷';
        thumbnailRow.appendChild(slot);
    }

    // Delete handlers
    thumbnailRow.querySelectorAll('.thumb-delete').forEach(btn => {
        btn.addEventListener('click', (e) => {
            const idx = parseInt(btn.dataset.index);
            state.photos.splice(idx, 1);
            renderThumbnails();
            updateCameraUI();
        });
    });
}

